import org.apache.kafka.clients.consumer.ConsumerConfig;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.apache.kafka.clients.consumer.ConsumerRecords;
import org.apache.kafka.clients.consumer.KafkaConsumer;
import org.apache.kafka.common.errors.WakeupException;
import org.apache.kafka.common.serialization.StringDeserializer;

import java.time.Duration;
import java.util.Collections;
import java.util.Properties;
import java.util.UUID;

/**
 * A Kafka consumer that processes inventory updates from the 'inventory-updates' topic.
 * Implements idempotent message processing following Kafka ecosystem patterns.
 */
public class InventoryConsumer {
    private final String bootstrapServers;
    private final String groupId;
    private final KafkaConsumer<String, String> consumer;
    private volatile boolean shutdown;

    public InventoryConsumer(String bootstrapServers) {
        this.bootstrapServers = bootstrapServers;
        this.groupId = "inventory-consumer-group";
        this.consumer = createConsumer();
        this.shutdown = false;
    }

    /**
     * Creates and configures the Kafka consumer with best practices.
     * Uses ConsumerConfig constants for all configuration keys.
     */
    private KafkaConsumer<String, String> createConsumer() {
        Properties props = new Properties();

        // Use ConsumerConfig constants instead of string literals
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        props.put(ConsumerConfig.GROUP_ID_CONFIG, groupId);
        props.put(ConsumerConfig.CLIENT_ID_CONFIG, "inventory-consumer-" + UUID.randomUUID());
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class.getName());
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class.getName());
        props.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, false);
        props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest");
        props.put(ConsumerConfig.MAX_POLL_RECORDS_CONFIG, 100);

        return new KafkaConsumer<>(props);
    }

    /**
     * Starts consuming messages from the inventory-updates topic.
     * Processes messages idempotently with manual offset commits.
     */
    public void start() {
        try {
            consumer.subscribe(Collections.singletonList("inventory-updates"));

            while (!shutdown) {
                try {
                    // Use poll(Duration) API - not the deprecated poll(long)
                    ConsumerRecords<String, String> records = consumer.poll(Duration.ofSeconds(1));

                    if (!records.isEmpty()) {
                        // Process each batch of records
                        for (ConsumerRecord<String, String> record : records) {
                            processMessage(record);
                        }

                        // Commit offsets after processing each batch
                        // This ensures idempotent processing
                        consumer.commitSync();
                    }
                } catch (WakeupException e) {
                    // Expected when shutdown is called
                    if (!shutdown) {
                        throw e;
                    }
                }
            }
        } catch (WakeupException e) {
            // Expected on shutdown, handle gracefully
            System.out.println("Consumer shutdown initiated via WakeupException");
        } finally {
            consumer.close();
        }
    }

    /**
     * Processes an individual inventory update message.
     * In a real application, this would update inventory state idempotently.
     */
    private void processMessage(ConsumerRecord<String, String> record) {
        // Example idempotent processing:
        // In production, use the message key and offset as a unique identifier
        // to ensure messages are processed exactly once even if reprocessed
        System.out.printf("Processing inventory update: key=%s, value=%s, partition=%d, offset=%d%n",
                record.key(), record.value(), record.partition(), record.offset());
    }

    /**
     * Gracefully shuts down the consumer.
     * Triggers WakeupException in the poll loop for clean shutdown.
     */
    public void shutdown() {
        shutdown = true;
        consumer.wakeup();
    }

    /**
     * Main entry point for the consumer.
     */
    public static void main(String[] args) {
        String bootstrapServers = args.length > 0 ? args[0] : "localhost:9092";

        InventoryConsumer inventoryConsumer = new InventoryConsumer(bootstrapServers);

        // Add shutdown hook for graceful termination
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("Shutting down InventoryConsumer...");
            inventoryConsumer.shutdown();
        }));

        inventoryConsumer.start();
    }
}

